INSERT 
  INTO MA3_FACE_REC_API_LOG (
	  TRAD_DATE
	, USER_CIF_NO
	, FACE_TRANSACTION_ID
	, CUST_NO
	, TRAD_NO
	, TRAD_CLS
	, CHNL_GB
	, API_URL
	, DATA
	, RES_CODE
	, REGISTTIME
) VALUES (
 	  VARCHAR_FORMAT(CURRENT TIMESTAMP, 'YYYYMMDD')
	, #{userCifNo}
	, #{faceTransactionId}
	, #{custNo}
	, #{tradNo}
	, #{tradCls}
	, #{chnlGb}
	, #{apiUrl}
	, #{data}
	, #{resCode}
	, CURRENT TIMESTAMP
)
